import React, { useEffect, useState } from "react";
import {
    Card, CardContent, Box, Stack, Typography, Divider, Alert,
    IconButton, CircularProgress, Snackbar, Paper,
} from "@mui/material";
import QRCodeLib from "react-qr-code";
import ContentCopyIcon from '@mui/icons-material/ContentCopy';
import VisibilityIcon from '@mui/icons-material/Visibility';
import VisibilityOffIcon from '@mui/icons-material/VisibilityOff';
import ShieldIcon from '@mui/icons-material/Shield';
import QrCode2Icon from '@mui/icons-material/QrCode2';

// react-qr-code default export shim (matches existing IdentityDisplay.tsx / IdentityCard.tsx pattern).
// Some bundlers resolve the CJS default to an object containing the component instead of the
// component itself, which makes <QRCodeLib /> throw "Element type is invalid".
// eslint-disable-next-line @typescript-eslint/no-explicit-any
const QRCode: React.ComponentType<{ value: string; size?: number; level?: 'L' | 'M' | 'Q' | 'H' }> =
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    (QRCodeLib as any).QRCode || (QRCodeLib as any).default || (QRCodeLib as any);

import { CallStatus } from "@/types/api.types";
import { AuthServices, AuthServicesError } from "@/api";
import { useAuthStore } from "@/store";
import { ApiGlobalStateManager } from "@/lib/api-state";
import { StatusMessage } from "@/components/StatusMessage";
import { PageContainer } from "@/components/PageContainer";

/**
 * Authenticator-app setup screen, ported from SaleOnePos's `SecurityPage` design.
 * Shows the QR code, formatted setup-key with show/hide + copy controls, and an
 * info note. The TOTP secret is fetched from `GET /auth/totp` and cached in the
 * auth store so flipping tabs doesn't refetch.
 */
export const OfflineOtp: React.FC = () => {
    const { totpSetupState, setTotpSetupState } = useAuthStore();
    const [showSecret, setShowSecret] = useState(false);
    const [snackOpen, setSnackOpen] = useState(false);
    const [snackMsg, setSnackMsg] = useState('');
    const hasFetchedRef = React.useRef<boolean>(false);

    useEffect(() => {
        if (!hasFetchedRef.current && totpSetupState.status !== CallStatus.Success) {
            hasFetchedRef.current = true;
            ApiGlobalStateManager(AuthServices.GetTotpSetup(), setTotpSetupState);
        }
    }, [totpSetupState.status, setTotpSetupState]);

    const setup = totpSetupState.status === CallStatus.Success ? totpSetupState.data : null;
    const formattedSecret = setup?.secret
        ? setup.secret.match(/.{1,4}/g)?.join(' ') ?? setup.secret
        : '';

    const copySecret = async () => {
        if (!setup?.secret) return;
        try {
            await navigator.clipboard.writeText(setup.secret);
            setSnackMsg('Secret copied');
        } catch {
            setSnackMsg('Copy failed — long-press to select');
        }
        setSnackOpen(true);
    };

    return (
        <PageContainer
            icon={<QrCode2Icon color="primary" />}
            title="Authenticator app"
            subtitle="Set up Google / Microsoft Authenticator (or any RFC 6238 TOTP app) for two-factor login."
        >
            <Card sx={{ mb: 2 }}>
                <CardContent>
                    <Typography variant="subtitle1" sx={{ mb: 0.5, fontWeight: 600 }}>
                        Two-factor login with an authenticator app
                    </Typography>
                    <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
                        Scan the QR code below in Google Authenticator, Microsoft Authenticator,
                        Authy, 1Password, or any RFC 6238 TOTP app. After scanning, you can sign
                        in with the 6-digit code from the app instead of (or in addition to) the
                        email OTP — both are accepted.
                    </Typography>

                    {totpSetupState.status === CallStatus.InProgress && (
                        <Box sx={{ display: 'flex', justifyContent: 'center', py: 6 }}>
                            <CircularProgress />
                        </Box>
                    )}

                    {setup && (
                        <Stack spacing={3} sx={{ alignItems: 'center' }}>
                            <Paper
                                elevation={0}
                                sx={{
                                    p: 2,
                                    bgcolor: '#fff',
                                    borderRadius: 1,
                                    border: '1px solid',
                                    borderColor: 'divider',
                                    lineHeight: 0,
                                }}
                            >
                                <QRCode
                                    value={setup.otpauthUri}
                                    size={208}
                                    level="M"
                                />
                            </Paper>

                            <Box sx={{ width: '100%' }}>
                                <Typography variant="caption" color="text.secondary" sx={{ display: 'block', mb: 0.5 }}>
                                    Account
                                </Typography>
                                <Typography
                                    variant="body2"
                                    sx={{ mb: 2, fontFamily: 'monospace', wordBreak: 'break-all' }}
                                >
                                    {setup.issuer}: {setup.accountName}
                                </Typography>

                                <Divider sx={{ my: 2 }} />

                                <Typography variant="caption" color="text.secondary" sx={{ display: 'block', mb: 0.5 }}>
                                    Can't scan? Enter this setup key manually
                                </Typography>
                                <Stack direction="row" spacing={1} sx={{ alignItems: 'center' }}>
                                    <Typography
                                        variant="body2"
                                        sx={{
                                            flex: 1,
                                            fontFamily: 'monospace',
                                            letterSpacing: 1,
                                            wordBreak: 'break-all',
                                            filter: showSecret ? 'none' : 'blur(6px)',
                                            transition: 'filter 0.2s',
                                            userSelect: showSecret ? 'all' : 'none',
                                        }}
                                    >
                                        {formattedSecret}
                                    </Typography>
                                    <IconButton
                                        size="small"
                                        onClick={() => setShowSecret(v => !v)}
                                        aria-label={showSecret ? 'Hide secret' : 'Show secret'}
                                    >
                                        {showSecret
                                            ? <VisibilityOffIcon fontSize="small" />
                                            : <VisibilityIcon fontSize="small" />}
                                    </IconButton>
                                    <IconButton size="small" onClick={copySecret} aria-label="Copy secret">
                                        <ContentCopyIcon fontSize="small" />
                                    </IconButton>
                                </Stack>
                                <Typography variant="caption" color="text.secondary" sx={{ display: 'block', mt: 1 }}>
                                    Algorithm: SHA1 · Digits: 6 · Period: 30s
                                </Typography>
                            </Box>
                        </Stack>
                    )}

                    <StatusMessage
                        currentStatus={
                            totpSetupState.status === CallStatus.Failure ||
                            totpSetupState.status === CallStatus.Throttled ||
                            totpSetupState.status === CallStatus.BadRequest
                                ? totpSetupState.status
                                : CallStatus.NotStarted
                        }
                        notStartedMessage=""
                        failureMessage={AuthServicesError.GetTotpSetupError(totpSetupState.httpStatus)}
                        correlationId={totpSetupState.correlationId}
                    />
                </CardContent>
            </Card>

            <Alert severity="info" icon={<ShieldIcon />}>
                <Typography variant="body2" sx={{ mb: 0.5, fontWeight: 600 }}>
                    About this code
                </Typography>
                <Typography variant="caption" component="div">
                    The setup key is derived from your account's security key — it isn't stored
                    on the server. If you lose access to your authenticator app, request an
                    email OTP at sign-in to log back in. Resetting your authentication (next
                    tab) will invalidate this QR code; you'll need to scan the new one.
                </Typography>
            </Alert>

            <Snackbar
                open={snackOpen}
                autoHideDuration={2200}
                onClose={() => setSnackOpen(false)}
                message={snackMsg}
                anchorOrigin={{ vertical: 'bottom', horizontal: 'center' }}
            />
        </PageContainer>
    );
};
